import React from "react";
import Container from 'react-bootstrap/Container';
import "../styles/contact.css";
import "../index.css";
import Header from "../components/Header.js"
import Footer from "../components/Footer.js"
import ReactContactForm from 'react-mail-form';
import Card from 'react-bootstrap/Card';
import {Row, Col} from 'react-bootstrap';
import { FaCodeBranch } from "react-icons/fa";

class Contact extends React.Component {
    render() {
        return (
            <div id="contact" className="page">
                <Header />
                <Container style={{marginTop: "50px", marginBottom: "50px"}}>
                    <h1>Contact Me</h1>
                    <p>Please use this form with any inquiries.</p>
                </Container>

                <Container style={{width:"100%"}}>
                    <Row>
                        <Col>

                        <img src={require("../images/coder.png")} variant="top" src={this.props.image}/>
                        </Col>
                        <Col xs={8}>
                        <Card.Body>
                        <Card.Title className="text-muted"><h1>{this.props.film}</h1></Card.Title>
                        <p>{this.props.reviewp1}</p>
                        <p>{this.props.reviewp2}</p>
                        <p>{this.props.reviewp3}</p>
                        <p>{this.props.reviewp4}</p>
                        <p>{this.props.reviewp5}</p>
                        </Card.Body>
                        </Col>
                        </Row>


                </Container>
                <Footer />
            </div>
        );
    }
}

export default Contact;
